/// |           _msg_type            |              room_type              |             r_type_locked             |                                                                                                                                                           sequence                                                                                                                                                            |
/// +---+---+---+---+---+---+---+---+---+---+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+
///
///  Field           Bits   Offset     Description
///  _msg_type       8      byte 0:0   ClientMessage::RoomType
///  room_type       8      byte 1:0   Always 2 (password)
///  r_type_locked   8      byte 2:0   1=locked
///  sequence        64     byte 3:0   Password (8 bytes)
use deku::{DekuRead, DekuWrite};

use crate::protocol::ClientMessage;

#[derive(Debug, Clone, Copy, DekuRead, DekuWrite)]
pub struct RoomTypePassword {
    _msg_type: u8,

    pub room_type: u8,
    pub r_type_locked: u8,
    pub sequence: [u8; 8],
}

impl RoomTypePassword {
    pub fn new(room_type: u8, r_type_locked: u8, sequence: [u8; 8]) -> Self {
        Self {
            _msg_type: ClientMessage::RoomType as u8,
            room_type,
            r_type_locked,
            sequence,
        }
    }
}
